import React from 'react';
import GoogleLogin from 'react-google-login';

const clientId = "1059585472363-vn4ejudkdn6fkncnnebcjoiga8bh17bt.apps.googleusercontent.com";

const GoogleButton = ({ onSocial }) =>{
    const onSuccess = async(response) => {
    	console.log(response);

        const { googleId, profileObj : { email, name } } = response;

        await onSocial({
            socialId : googleId,
            socialType : 'google',
            email,
            nickname : name
        });

        console.log("ID: " + response.sub);
        console.log('Full Name: ' + response.name);
        console.log('Given Name: ' + response.given_name);
        console.log('Family Name: ' + response.family_name);
        console.log("Image URL: " + response.picture);
        console.log("Email: " + response.email); 
    }

    const onFailure = (error) => {
        console.log(error);
    }

    return(
        <div>
            <GoogleLogin
                clientId={clientId}
                responseType={"id_token"}
                onSuccess={onSuccess}
                onFailure={onFailure}/>
        </div>
    )
}
export default GoogleButton;
